fn logical_stack_for(&self, task_id: AsyncTaskId) -> Vec<AsyncTaskId> {
  let mut stack = vec![task_id];
  let mut current = Some(task_id);
  while let Some(id) = current {
    if let Some(parent) = self.parents.get(&id) {
      if let Some(pid) = *parent {
        stack.push(pid);
        current = Some(pid);
      } else { break; }
    } else { break; }
  }
  stack.reverse();
  stack
}
